@table_category = CNST_TABLECATEGORY_UPBS_ACCT_RULE; //[upbs_acct_rule]

//判断事务号大小并记录本次事务号.
<M>[通用SQL执行][select transaction_no
                  from uarg_syncinfo
                 where table_name = @table_name
                   and position_str = @position_str
                   for update][count = @sql_row_count][transaction_no = @transaction_no_t]
//新增记录
if (0 == @sql_row_count)
{
  [继续执行]
  // 输出了查询的字段即等同使用了select..into语句,预览中会判断sql_row_count!=1时设置错误信息,因此需要重置错误信息.

  <M>[插入DB表记录][uarg_syncinfo][]
  [处理失败]
  {
    <W>[事务内报错返回][ERR_EXEC_SQL_FAIL][@table_name,@position_str,@transaction_no,@param_oper_type]
  }
  else
  {
    [事务处理结束]
  }
}
//更新记录
else if (@transaction_no > @transaction_no_t)
{
  <M>[通用SQL执行][update uarg_syncinfo
                     set transaction_no = @transaction_no
                   where table_name = @table_name
                     and position_str = @position_str][count = @sql_row_count][]
  [处理失败]
  {
    <W>[事务内报错返回][ERR_EXEC_SQL_FAIL][@table_name,@position_str,@transaction_no,@param_oper_type,@transaction_no_t]
  }
  else
  {
    [事务处理结束]

    if (0 == @sql_row_count)
    {
      [直接返回]
    }
  }
}
//抛弃消息.
else
{
  [事务处理结束]
  [直接返回]
}

